class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int totalOnes = 0;
        for (int num : nums) {
            totalOnes += num;
        }
        int maxScore = totalOnes;
        int currentScore = totalOnes;
        List<Integer> result = new ArrayList<>();
        result.add(0);
        for (int i = 0; i < n; i++) {
            if (nums[i] == 0) {
                currentScore++;
            } else {
                currentScore--;
            }
            if (currentScore > maxScore) {
                maxScore = currentScore;
                result.clear();
                result.add(i + 1);
            } else if (currentScore == maxScore) {
                result.add(i + 1);
            }
        }
        return result;
    }
}
